import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"超级管理员","description":"","frontmatter":{},"headers":[],"relativePath":"zh/features/super-admin.md","filePath":"zh/features/super-admin.md"}'),c={name:"zh/features/super-admin.md"};function d(l,a,n,o,r,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="超级管理员" tabindex="-1">超级管理员 <a class="header-anchor" href="#超级管理员" aria-label="Permalink to &quot;超级管理员&quot;">​</a></h1><p><code>super_admin</code> 角色由 <code>clearance:install</code> 自动创建，并与所有 <code>clearance-*</code> 权限保持同步。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>完整的安装程序参数列表请参见<a href="/clearance-docs/zh/guide/installation.html">安装指南</a>和 <a href="/clearance-docs/zh/api/artisan-commands.html">Artisan 命令参考</a>。</p><h2 id="gate-绕过-可选启用" tabindex="-1">Gate 绕过（可选启用） <a class="header-anchor" href="#gate-绕过-可选启用" aria-label="Permalink to &quot;Gate 绕过（可选启用）&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> 控制 <code>super_admin</code> 角色是否通过一个 <code>Gate::before()</code> 钩子，在全局范围内绕过所有 Laravel 的 <code>can()</code>/<code>Gate::allows()</code>/策略检查。默认值：<code>false</code>。该绕过是可选启用的。要启用它：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">应用范围内，而非仅限于面板范围</p><p>启用后，任何持有 <code>super_admin</code> 的用户都会跳过整个应用范围内的<strong>所有</strong> Gate 检查——不仅仅是 Clearance 面板的检查。这会影响你应用中每一个 <code>can()</code>、<code>Gate::allows()</code> 和策略检查，而不仅仅是 Clearance 定义的那些。若需要更窄的范围，请保持关闭，改为显式地授予权限。</p></div><h2 id="别名检测" tabindex="-1">别名检测 <a class="header-anchor" href="#别名检测" aria-label="Permalink to &quot;别名检测&quot;">​</a></h2><p>如果你的数据库中已经存在一个名为 <code>super_admin</code>、<code>superadmin</code>、<code>super-admin</code>、<code>root</code> 或 <code>owner</code> 的角色，安装程序会检测到它，并交互式地提示你将其提升，或创建一个单独的 <code>super_admin</code>。使用 <code>--super-admin-role=NAME</code> 可以跳过该提示：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">提升是非破坏性的</p><p>提升会原地重命名该角色——所有现有的 <code>model_has_roles</code> 分配都会通过 <code>role_id</code> 上的外键被保留。在提升过程中，没有任何用户会丢失其现有的角色分配。</p></div><h2 id="面板访问与精细化的写权限" tabindex="-1">面板访问与精细化的写权限 <a class="header-anchor" href="#面板访问与精细化的写权限" aria-label="Permalink to &quot;面板访问与精细化的写权限&quot;">​</a></h2><p>安装完成后访问 <code>/clearance</code>。对整个面板的读访问需要 <code>clearance-access</code> 权限，通过 <code>can()</code> 检查，绝不通过 <code>hasRole()</code>：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>每个分区的写操作都由一个专属的、可委派的权限控制——全部由 <code>clearance:install</code> 创建并分配给 <code>super_admin</code>：</p><table tabindex="0"><thead><tr><th>权限</th><th>控制内容</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>创建/编辑/删除权限</td></tr><tr><td><code>clearance-roles-write</code></td><td>创建/编辑/删除角色及其权限分配</td></tr><tr><td><code>clearance-guards-write</code></td><td>创建/编辑/删除看守器</td></tr><tr><td><code>clearance-settings-write</code></td><td>编辑显示元数据、图标、颜色、默认角色</td></tr><tr><td><code>clearance-users-write</code></td><td>为特定用户分配/移除角色</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">授予窄范围的访问权限</p><p>将 <code>clearance-access</code> 与恰好一个 <code>clearance-{section}-write</code> 权限组合，即可把某个面板分区（例如角色）的写权限交给某个用户（比如一位团队负责人），而不会暴露设置、看守器或用户管理。</p></div><p>如果某个精细化权限记录在数据库中完全不存在（一种历史遗留的、未预置的状态），检查会回退到 <code>clearance-access</code>，以保持向后兼容。在任何已经运行过 <code>clearance:install</code> 的实例上，这个回退逻辑永远不会被触发。</p><h2 id="受保护的-clearance-权限" tabindex="-1">受保护的 <code>clearance-*</code> 权限 <a class="header-anchor" href="#受保护的-clearance-权限" aria-label="Permalink to &quot;受保护的 \`clearance-*\` 权限&quot;">​</a></h2><p><code>clearance-*</code> 权限是被保留的：除了通过该包自身的安装流程之外，任何人都无法创建、重命名、删除它们，也无法将其添加到任何角色——即使是 <code>super_admin</code> 本身的操作者，针对 <code>super_admin</code> 角色本身也不例外。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/features/permissions.html">权限</a>——通用的权限 CRUD 面板（不包含 <code>clearance-*</code>）。</li><li><a href="/clearance-docs/zh/features/roles.html">角色</a>——将 <code>clearance-*-write</code> 权限分配给一个自定义角色。</li><li><a href="/clearance-docs/zh/guide/security.html">安全性</a>——完整的权限提升与上限模型。</li></ul>`,24)])])}const u=e(c,[["render",d]]);export{k as __pageData,u as default};
